import os
from functools import lru_cache

class IndexCache:
    def __init__(self, index_file_path):
        self.index_file_path = index_file_path
        self.cache = lru_cache(maxsize=None)  # Use an LRU cache with no max size

    def get(self, key):
        return self.cache.get(key)

    def set(self, key, value):
        self.cache[key] = value

    def delete(self, key):
        del self.cache[key]

    def save(self):
        # Save the cache to the index file
        with open(self.index_file_path, 'wb') as f:
            import pickle
            pickle.dump(self.cache, f)

    @classmethod
    def load(cls, index_file_path):
        # Load the cache from the index file
        if not os.path.exists(index_file_path):
            return cls(index_file_path)
        with open(index_file_path, 'rb') as f:
            import pickle
            cache = pickle.load(f)
            return cls(index_file_path), cache
